#include<bits/stdc++.h>
using namespace std;
int n,a[205],dp[205][205],s[205],dp2[205][205],ans1=0x3f3f3f3f,ans2;
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++) cin>>a[i],s[i]=s[i-1]+a[i];
    for(int i=1;i<=n;i++)
    {
        a[i+n]=a[i];
        s[i+n]=s[i+n-1]+a[i+n];
    }
    n+=n;
	for(int len=2;len<=n;len++)
	{
		for(int i=1;i<=n-len+1;i++)
		{
			int j=i+len-1;
            dp[i][j]=0x3f3f3f3f;
			for(int k=i;k<j;k++)
			{
				dp[i][j]=min(dp[i][j],dp[i][k]+dp[k+1][j]+s[j]-s[i-1]);
                dp2[i][j]=max(dp2[i][j],dp2[i][k]+dp2[k+1][j]+s[j]-s[i-1]);
			}
		}
	}
    n/=2;
    for(int i=1;i<=n;i++)
    {
        ans1=min(ans1,dp[i][i+n-1]);
        ans2=max(ans2,dp2[i][i+n-1]);
    }
	cout<<ans1<<'\n'<<ans2;
	return 0;
}
